INSERT INTO `mailtemplate` (`id`, `name`, `value`, `provider`, `changeTimestamp`) VALUES
(1,	'icsappointment_delete.twig',	'{% block content %}\r\nBEGIN:VCALENDAR\r\nX-LOTUS-CHARSET:UTF-8\r\nCALSCALE:GREGORIAN\r\nVERSION:2.0\r\nPRODID:ZMS-München\r\nMETHOD:CANCEL\r\nX-WR-TIMEZONE:Europe/Berlin\r\nBEGIN:VTIMEZONE\r\nTZID:Europe/Berlin\r\nX-LIC-LOCATION:Europe/Berlin\r\nBEGIN:DAYLIGHT\r\nTZOFFSETFROM:+0100\r\nTZOFFSETTO:+0200\r\nTZNAME:CEST\r\nDTSTART:19700329T020000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=3\r\nEND:DAYLIGHT\r\nBEGIN:STANDARD\r\nTZOFFSETFROM:+0200\r\nTZOFFSETTO:+0100\r\nTZNAME:CET\r\nDTSTART:19701025T030000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=10\r\nEND:STANDARD\r\nEND:VTIMEZONE\r\nBEGIN:VEVENT\r\nUID:{{ startTime|date(\"Ymd\") }}-{{ process.displayNumber }}\r\nORGANIZER;CN=\"{{ process.scope.provider.displayName }}\":MAILTO:{{ process.scope.preferences.client.emailFrom }}\r\nSEQUENCE:0\r\nLOCATION:{{ process.scope.provider.displayName }} {{ process.scope.provider.contact.street }} {{ process.scope.provider.contact.streetNumber }}\\, {{ process.scope.provider.contact.postalCode }} {{ process.scope.provider.contact.city }}\r\nGEO:48.85299;2.36885\r\nSUMMARY:{{ \"Terminabsage:\"|trans }} {{ process.displayNumber }}\r\nDESCRIPTION:{{ message }}\r\nCLASS:PUBLIC\r\nDTSTART;TZID=Europe/Berlin:{{ startTime|date(\"Ymd\") }}T{{ startTime|date(\"His\") }}\r\nDTEND;TZID=Europe/Berlin:{{ endTime|date(\"Ymd\") }}T{{ endTime|date(\"His\") }}\r\nDTSTAMP:{{ timestamp|date(\"Ymd\") }}T{{ timestamp|date(\"His\") }}\r\nSTATUS:CANCELLED\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n{% endblock %}\r\n',	'',	'2026-02-13 13:38:37'),
(2,	'icsappointment.twig',	'{% block content %}\r\nBEGIN:VCALENDAR\r\nX-LOTUS-CHARSET:UTF-8\r\nCALSCALE:GREGORIAN\r\nVERSION:2.0\r\nPRODID:ZMS-München\r\nX-WR-TIMEZONE:Europe/Berlin\r\nBEGIN:VTIMEZONE\r\nTZID:Europe/Berlin\r\nX-LIC-LOCATION:Europe/Berlin\r\nBEGIN:DAYLIGHT\r\nTZOFFSETFROM:+0100\r\nTZOFFSETTO:+0200\r\nTZNAME:CEST\r\nDTSTART:19700329T020000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=3\r\nEND:DAYLIGHT\r\nBEGIN:STANDARD\r\nTZOFFSETFROM:+0200\r\nTZOFFSETTO:+0100\r\nTZNAME:CET\r\nDTSTART:19701025T030000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=10\r\nEND:STANDARD\r\nEND:VTIMEZONE\r\nBEGIN:VEVENT\r\nUID:{{ startTime|date(\"Ymd\") }}-{{ process.displayNumber }}\r\nLOCATION:{{ process.scope.provider.displayName }}: {{ process.scope.provider.contact.street }} {{ process.scope.provider.contact.streetNumber }}, {{ process.scope.provider.contact.postalCode }} {{ process.scope.provider.contact.city }}\r\nGEO:48.85299;2.36885\r\nSUMMARY: {{ process.requests|reduce((carry, req) => carry|merge({ (req.name): (carry[req.name] is defined ? carry[req.name] + 1 : 1) }), {})|map((count, name) => (count > 1 ? count ~ \'x \' : \'\') ~ name)|join(\', \') }} \r\nDESCRIPTION:Terminnummer: {{ process.displayNumber }}\\n\\nLeistung:\\n{% for requestGroup in requestGroups %}{{ requestGroup[\'count\'] }}x {{ requestGroup[\'request\'].name }}: https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}{% if not loop.last %}\\n{% endif %}{% endfor %}\\n\\nIhnen ist etwas dazwischengekommen? Sagen Sie Ihren Termin ab oder verschieben Sie Ihren Termin:\\n{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\\n\r\nCLASS:PUBLIC\r\nDTSTART;TZID=Europe/Berlin:{{ startTime|date(\"Ymd\") }}T{{ startTime|date(\"His\") }}\r\nDTEND;TZID=Europe/Berlin:{{ endTime|date(\"Ymd\") }}T{{ endTime|date(\"His\") }}\r\nDTSTAMP:{{ timestamp|date(\"Ymd\") }}T{{ timestamp|date(\"His\") }}\r\nBEGIN:VALARM\r\nACTION:DISPLAY\r\nDESCRIPTION:{{ \"München-TerminMUC:\"|trans }} {{ process.displayNumber }}\r\nTRIGGER:-P1D\r\nEND:VALARM\r\nSTATUS:CONFIRMED\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n{% endblock %}\r\n',	'',	'2026-02-13 13:38:37'),
(3,	'mail_admin_delete.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set bookLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nwir mussten Ihren Termin absagen.\r\n<br><br>\r\n—\r\n<br><br>\r\n<strong> Terminnummer: {{ process.displayNumber }} </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n---\r\n<br><br>\r\n<strong> Begründung:</strong>\r\nLeider erfüllen Sie nicht die Voraussetzungen für die gebuchte Dienstleistung oder Sie haben mehrere Termine für die gleiche Dienstleistung gebucht.\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n<script type=\"application/ld+json\">\r\n{\r\n  \"@context\": \"http://schema.org\",\r\n  \"@type\": \"EventReservation\",\r\n  \"reservationNumber\": \"{{ process.displayNumber }}\",\r\n  \"reservationStatus\": \"http://schema.org/Confirmed\",\r\n  \"modifyReservationUrl\": \"{{ config.appointments.urlAppointments }}\",\r\n  \"modifiedTime\": \"{{ process.createTimestamp|date(\'c\') }}\",\r\n  \"underName\": {\r\n    \"@type\": \"Person\",\r\n    \"name\": \"{{ client.familyName }}\"\r\n  },\r\n  \"reservationFor\": {\r\n    \"@type\": \"Event\",\r\n    \"name\": \"{% for request in process.requests %}{{ request.name }}{% if not loop.last %},{% endif %} {% endfor %}\",\r\n    \"startDate\": \"{{ date|date(\'c\') }}\",\r\n    \"location\": {\r\n      \"@type\": \"Place\",\r\n      \"name\": \"{{ process.scope.provider.name }}\",\r\n      \"url\": \"{{process.scope.provider.link}}\",\r\n      \"geo\": {\r\n        \"@type\": \"GeoCoordinates\",\r\n        \"latitude\": \"{{process.scope.provider.contact.lat}}\",\r\n        \"longitude\": \"{{process.scope.provider.contact.lon}}\"\r\n      },\r\n      \"address\": {\r\n        \"@type\": \"PostalAddress\",\r\n        \"streetAddress\": \"{{process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber}}\",\r\n        \"addressLocality\": \"{{process.scope.provider.contact.city}}\",\r\n        \"addressRegion\": \"{{process.scope.provider.contact.city}}\",\r\n        \"postalCode\": \"{{process.scope.provider.contact.postalCode}}\",\r\n        \"addressCountry\": \"DE\"\r\n      }\r\n    }\r\n  }\r\n}\r\n</script>\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(4,	'mail_admin_update.twig',	'{% block german %}\r\n{% if process.queue.withAppointment %}\r\nGeändert wurde der Termin von {{ process.clients|first.familyName }} (Vorgangsnummer: {{ process.displayNumber }})\r\nam {{ process.appointments|first.date|format_date(pattern=\"EE dd. MMMM y\") }} um {{ process.appointments|first.date|date(\"H:i\") }} Uhr\r\n{% else %}\r\nEinem Spontankunden mit der Wartenummer {{ process.displayNumber }} wurde am {{ now|format_date(pattern=\"EE dd. MMMM y\") }} der Termin geändert\r\n{% endif %} für den Standort {{ process.scope.contact.name }}{% if process.scope.shortName %} {{ process.scope.shortName }}{% endif %}, {{ process.scope.contact.street }}{% if process.scope.shortName %} {{ process.scope.contact.streetNumber }}{% endif %}.\r\n<br /><br />\r\nDie Terminänderung wurde initiiert via \"{{ initiator }}\".\r\n<br /><br />\r\nDies ist ein Service Ihres ZMS.\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(5,	'mail_confirmation.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n       Sie haben folgenden Termin bei uns gebucht:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zur Vorbereitung:</strong>\r\n<br>\r\n<ul>\r\n  {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    <li>Im Anhang finden Sie außerdem eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n   {% endif %}\r\n    <li>Im Anhang finden Sie eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n    <li>Stellen Sie sicher, dass Sie alle Voraussetzungen für die gebuchten Leistungen erfüllen.</li>\r\n    <li>Bringen Sie alle benötigten Unterlagen zum Termin mit.</li>\r\n</ul>\r\n<br>\r\n——\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\"><strong>Termin absagen oder verschieben</strong></a><br />\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n {#{{ block(\"sendoff_bb\") }}  je nach Behörde#}\r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}\r\n',	'',	'2026-02-13 13:38:37'),
(6,	'mail_delete.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set bookLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nIhr Termin wurde abgesagt:\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong> Terminnummer: {{ process.displayNumber }} </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n——\r\n<br><br>\r\nDanke, dass Sie Ihren Termin für andere freigegeben haben. \r\n<br><br>\r\n{{ block(\"sendoff_munich\") }}\r\n{#{{ block(\"sendoff_bb\") }}  je nach Behörde#}\r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'',	'2026-02-13 13:38:37'),
(7,	'mail_pickup.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    {{ block(\"autogenerated_top_german\") }}\r\n    {{ block(\"salutation_german\") }}\r\n    {% for request in process.requests %}\r\n    Ihr Dokument {% if request.name %}({{ request.name }}){% endif %} ist fertig und liegt zur Abholung bereit.<br />\r\n    {% endfor %}\r\n    <br />\r\n    Die Adresse lautet: {{ process.scope.provider.displayName ~ \" \" ~ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber ~\", \" ~ process.scope.provider.contact.postalCode ~ \" \" ~ process.scope.provider.contact.city }}.\r\n    <br /><br />\r\n    {{ block(\"sendoff_german\") }}\r\n{% endblock %}\r\n',	'',	'2024-05-23 10:45:16'),
(8,	'mail_preconfirmed.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set confirmLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nbitte aktivieren Sie den folgenden Termin innerhalb von {{ process.scope.preferences.appointment.activationDuration }} Minuten, sonst verfällt Ihre Reservierung. Klicken Sie auf den folgenden Link, um Ihre Terminbuchung abzuschließen:\r\n<br>\r\n<strong><a href=\"{{ confirmLink }}\" target=\"_blank\">Termin aktivieren</a></strong>  <br /><br />\r\n\r\n<br>\r\n——\r\n<br><br>\r\n<strong> Ausgewählter Termin: </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n——\r\n<br><br>\r\nNach Aktivierung des Termins erhalten Sie eine Bestätigung mit Terminnummer und weiteren Informationen zu Ihrem Termin.\r\n<br><br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{#{{ block(\"sendoff_bb\") }}  je nach Behörde#}\r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'',	'2026-02-13 13:38:37'),
(9,	'mail_queued.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"autogenerated_top_german\") }}\r\n{{ block(\"salutation_german\") }}\r\nhiermit bestätigen wir Ihre Wartenummer für den \r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd. MMMM y\") }}\r\n<br /><br />\r\n<strong>Ort:</strong> {{ process.scope.provider.displayName ~ \" \" ~ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber ~\", \" ~ process.scope.provider.contact.postalCode ~ \" \" ~ process.scope.provider.contact.city }}<br />\r\n{% if process.scope.hint %}\r\n({{ process.scope.hint }})<br />\r\n{% endif %}<br />\r\nIhre Wartenummer ist die <strong>\"{{ process.displayNumber }}\"</strong><br /><br />\r\n{% if process.scope.provider.source == \"dldb\" and process.scope.provider.data.payment %}\r\nZahlungshinweis: {{ process.scope.provider.data.payment }}<br /><br />\r\n{% endif %}\r\n{% if process.requests|length > 1 %}\r\n{% set requestalias = \"Dienstleistungen\" %}\r\n{% else %}\r\n{% set requestalias = \"Dienstleistung\" %}\r\n{% endif %}\r\n{% if process.requests|length == 0 %}\r\nSie haben keine Dienstleistungen ausgewählt.\r\n{% else %}\r\nSie haben folgende {{ requestalias }} ausgewählt:\r\n<br/><br />\r\n    {% for request in process.requests %}\r\n    <strong><a href=\"https://service.berlin.de/dienstleistung/{{ request.id }}/standort/{{ process.scope.provider.id }}/\">{{ request.name }} am Standort {{ process.scope.provider.displayName }}</a></strong><br/>\r\n    {% if request.source == \"dldb\" and request.data %}\r\n    <div style=\"border-left: 1em solid #ffffff; background: #ffffff;\">\r\n    {% include \"@zmsentities/detail/service_detail_prerequisites.twig\" with {\"service\":request.data, \"headerlevel\":\"h4\"} %}\r\n\r\n    {% include \"@zmsentities/detail/service_detail_requirements.twig\" with {\"service\":request.data, \"headerlevel\":\"h4\"} %}\r\n\r\n    {% include \"@zmsentities/detail/service_detail_fees.twig\" with {\"service\":request.data, \"headerlevel\":\"h4\"} %}\r\n    </div>\r\n    {% endif %}\r\n    {% if process.requests|length > 1 and not loop.last %}\r\n    <br /><br />\r\n    ----------------------\r\n    <br /><br />\r\n    {% endif %}\r\n    {% endfor %}\r\n{% endif %}\r\n<br /><br /><br />\r\n{{ block(\"sendoff_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(10,	'mail_reminder.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n      Sie haben in Kürze folgenden Termin bei uns:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zu Ihrem Besuch:</strong>\r\n<br>\r\n<ul>\r\n    {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    {% endif %}\r\n	<li>Bringen Sie alle benötigten Unterlagen zum Termin mit. Stellen Sie sicher, dass Sie mögliche Gebühren direkt vor Ort bezahlen können.</li>\r\n    <li>Kommen Sie bitte pünktlich. Zeigen Sie am Eingang diese E-Mail vor.  </li>\r\n    <li>Ihre Terminnummer wird vor Ort auf einem Bildschirm angezeigt. Sie sehen dort, wann Sie dran sind und wohin Sie gehen müssen.</li>\r\n    <li>In seltenen Fällen kann es vorkommen, dass Sie trotz Termin kurz warten müssen. Bitte haben Sie dafür Verständnis.</li>\r\n</ul>\r\n<br>\r\n——\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\"><strong>Termin absagen oder verschieben</strong></a><br />\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{#{{ block(\"sendoff_bb\") }}  je nach Behörde#}\r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}',	'',	'2026-02-13 13:38:37'),
(11,	'mail_scopeadmin_processlist.twig',	'{% block content %}\r\n<table cellpadding=\"0\" cellspacing=\"0\" width=\"1000\">\r\n    <tr>\r\n        <td valign=\"top\">\r\n            <h1>{{ scope.provider.displayName }}</h1>\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td valign=\"top\" style=\"padding:2px 0px;\">\r\n            Standortanschrift: {{ scope.contact.street }} {{ scope.contact.streetNumber }}\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td valign=\"top\" style=\"padding:2px 0px;\">\r\n            Standortbeschreibung: {{ scope.contact.name|default(\'-\') }}\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td valign=\"top\" style=\"padding:2px 0px;\">\r\n            Standortk&uuml;rzel: {{ scope.contact.shortName|default(\'-\') }}\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td valign=\"top\" style=\"padding:2px 0px;\">\r\n            Email Standortadmin: {{ scope.contact.email }}\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td>&nbsp;</td>\r\n    </tr>\r\n\r\n    <tr>\r\n        <td>\r\n            <strong>Termine am {{ dateTime|date(\"Y-m-d\") }} ({{ processList|length }} gesamt)</strong>\r\n        </td>\r\n    </tr>\r\n    <tr>\r\n        <td>&nbsp;</td>\r\n    </tr>\r\n    <tr>\r\n        <td>\r\n            <table>\r\n                <tr>\r\n                    <td bgcolor=\"#dedede\" style=\"padding:3px 10px;\">Uhrzeit</td>\r\n                    <td bgcolor=\"#dedede\" style=\"padding:3px 10px;\">Vorgangsnummer</td>\r\n                    <td bgcolor=\"#dedede\" style=\"padding:3px 10px;\">Name des Kunden</td>\r\n                    <td bgcolor=\"#dedede\" style=\"padding:3px 10px;\">Dienstleistung</td>\r\n                </tr>\r\n                {% for key, process in processList %}\r\n                {% set style = \"padding:3px 10px; background-color:#efefef; border-bottom:1px solid #e2e2e2;\" %}\r\n                {% if loop.index0 is odd %}\r\n                {% set style = \"padding:3px 10px;\" %}\r\n                {% endif %}\r\n                <tr>\r\n                    <td width=\"70\" valign=\"top\" style=\"{{ style }}\">\r\n                        {{ process.appointments|first.date|date(\"H:i\") }} {% if process.appointments|first.slotCount > 1 %}<small>({{ process.appointments|first.slotCount }})</small>{% endif %}\r\n                    </td>\r\n                    <td width=\"120\" valign=\"top\" style=\"{{ style }}\">\r\n                        {{ process.displayNumber }}\r\n                    </td>\r\n                    <td valign=\"top\" width=\"280\" style=\"{{ style }}\">\r\n                        {{ process.clients|first.familyName }}\r\n                    </td>\r\n                    <td valign=\"top\" width=\"430\" style=\"{{ style }}\">\r\n                        {{ process.requests|first.name }}\r\n                    </td>\r\n                </tr>\r\n                {% endfor %}\r\n            </table>\r\n        </td>\r\n    </tr>\r\n</table>\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(12,	'notification_appointment.twig',	'{% block german %}\r\nIhr Termin: Vorgangsnr. {{ process.displayNumber }} am {{ process.appointments.0.date|date(\'d.m.y\') }} um {{ process.appointments.0.date|date(\'H:i\') }} Uhr, {{ process.scope.provider.contact.name }}, {{ process.scope.provider.contact.street }} {{ process.scope.provider.contact.streetNumber }}, {{ process.scope.provider.contact.postalCode }}  {{ process.scope.provider.contact.city }} {% if process.scope.hint %}({{ process.scope.hint }}){% endif %}\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(13,	'notification_confirmation.twig',	'{% block german %}\r\n{% if process.scope.preferences.notifications.confirmationContent %}\r\n{{ process.scope.preferences.notifications.confirmationContent }} {{ process.displayNumber }}\r\n{% else %}\r\n{{ config.notifications.confirmationContent }} {{ process.displayNumber }}\r\n{% endif %}\r\n{% endblock %}',	'',	'2025-10-08 13:31:56'),
(14,	'notification_deleted.twig',	'{% block german %}\r\nIhr Termin: Vorgangsnr. {{ process.displayNumber }} am {{ process.appointments.0.date|date(\'d.m.y\') }} um {{ process.appointments.0.date|date(\'H:i\') }} Uhr, wurde abgesagt.\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(15,	'notification_headsup.twig',	'{% block german %}\r\n{% if process.scope.preferences.notifications.headsUpContent %}\r\n{{ process.scope.preferences.notifications.headsUpContent }} {{ process.displayNumber }}\r\n{% else %}\r\n{{ config.notifications.headsUpContent }} {{ process.displayNumber }}\r\n{% endif %}\r\n{% endblock %}',	'',	'2025-10-08 13:31:56'),
(16,	'notification_pickup.twig',	'{% block german %}\r\nIhr Dokument ist fertig und liegt zur Abholung bereit, am Standort {{ process.scope.provider.contact.name }}\r\n{% endblock %}\r\n',	'',	'2024-05-23 10:45:16'),
(17,	'snippets.twig',	'{% block autogenerated_top_german %}\r\n<div style=\"background: #eeeeee; border: 1px solid #aaaaaa; padding:10px;\">\r\nAchtung! Dies ist eine automatisch erstellte E-Mail. Bitte antworten Sie nicht auf diese Mail, sie kann nicht bearbeitet werden.\r\n</div><br />\r\n{% endblock %}\r\n\r\n{% block sendoff_german_female %}\r\nMit freundlichen Grüßen<br />\r\nIhre {{ process.scope.provider.displayName }} \r\n<br /><br />\r\n{% endblock %}\r\n\r\n{% block autogenerated_down_german %}\r\n<hr> \r\nDies ist eine automatisch erstellte Nachricht. Bitte antworten Sie nicht auf diese E-Mail.\r\n<br />\r\n{% endblock %}\r\n\r\n{% block mse_note %}\r\n<strong>Zur Wahrung des Datenschutzes muss vor Einsicht die Berechtigung geprüft werden. Deshalb sind folgende Unterlagen zum Termin mitzubringen:</strong><br>\r\n- Antrag auf Planeinsicht in Bestandspläne<br>\r\n- Grundbuchauszug, Kaufvertrag, Grundsteuerbescheid oder Bescheid der MSE<br>\r\n- Ausweisdokument<br>\r\n</p>\r\n\r\n<p>\r\nBei Einsicht durch eine bevollmächtigte Person ist <u>zusätzlich</u> die Vollmacht der Eigentümer*innen bzw. Erbbauberechtige*n vorzulegen. Bei Vertretung durch eine Hausverwaltung ist die Hausverwaltervollmacht vorzulegen.\r\n</p>\r\n\r\n<p>\r\nDas Antragsformular auf Planeinsicht und eine Mustervorlage für eine Vollmacht finden Sie auf unserer <a href=\"https://stadt.muenchen.de/service/info/team-planauskunft-und-planverwaltung-mse-4kp/10435225/\" target=\"_blank\">Homepage</a>.  \r\n</p>\r\n{% endblock %}\r\n\r\n{% block mse4_note %}\r\nAllgemeinen Informationen zum Vorgehen <a href=\"https://stadt.muenchen.de/service/info/anwesensentwaesserung/10435234/\">Verfahren der Plangenehmigung</a> finden Sie mit unseren Musterplänen sowie unseren <a href=\"https://stadt.muenchen.de/dam/jcr:a83b122a-ce80-48e1-9418-39b7a40987de/Leitfaden-Grundstuecksentwaesserung.pdf\">Leitfaden Planung und Bau</a> auf unserer Homepage.<br>\r\n<br>\r\n<p style=\"font-size:18px; font-weight: bold;\" >Bitte beachten Sie, dass keine pauschale Komplettprüfung erfolgen kann. Bringen Sie daher konkrete Fragestellungen zum Termin mit. Soll zum Termin ein Antrag abgegeben werden, achten Sie bitte auf Vollständigkeit der Antragsunterlagen:</p>\r\n<br>\r\n- Antragsformular<br>\r\n- Grundriss und Abwicklung im Maßstab 1:100 sowie Lageplan im Maßstab 1:1000<br>\r\n- Technisches Formblatt: Das Antragsformular finden Sie <a href=\"https://stadt.muenchen.de/service/info/erschliessungsbuero-mse-421/10435231/\">hier</a> (auch Klärung der <br>Einleitung von Niederschlagswasser).<br>\r\n</p>\r\n\r\n<p>\r\n<b>Ggf. sind weitere Unterlagen, in Abhängigkeit von Art und Umfang der Maßnahme, mitzubringen:</b><br>\r\n- Stellungnahme zu Altlastenverdachtsflächen hinsichtlich Versickerungsanlagen / Bescheid zur wasserrechtlichen Erlaubnis vom Referat für Klima- u. Umweltschutz<br>\r\n- Berechnungen zu Versickerungsanlagen (DWA-A 138 / DWA-M 153)<br>\r\n- Berechnungen zu Abscheideranlagen (DIN EN 1825-2 / DIN EN 858-2 / DIN 1999-100)<br>\r\n- Bereits eingesehene Bestandsunterlagen. Den Termin können Sie <a href=\"https://stadt.muenchen.de/service/info/team-planauskunft-und-planverwaltung-mse-4kp/10435225/\">hier</a> beantragen.\r\n</p>\r\n{% endblock %}\r\n\r\n{% block biometric_photo %}\r\n<strong>Hinweis zum biometrischen Passfoto:</strong><br />\r\n<br />\r\nDerzeit sind bei uns keine Fotoautomaten verfügbar. Bitte bringen Sie Ihr Foto zum Termin mit.\r\n<br />\r\n{% endblock %}\r\n\r\n{% block branddirektion %}\r\n<br><br>\r\n<strong>Hinweise:</strong>\r\n<br>\r\n<ul>\r\n  {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n   {% endif %}\r\n<li>Beachten Sie bitte, dass es für Fahrzeuge keine Parkmöglichkeit auf den Wachen gibt.</li>\r\n<li>Es könnte sein, dass wir aufgrund besonderer Einsatzlagen den Termin von unserer Seite stornieren müssen. In diesem Fall würden wir uns mit Ihnen in Verbindung setzten und einen Ausweichtermin buchen.</li>\r\n<li>Beachten Sie bitte die Sicherheitsanweisungen der Sie betreuenden Dienstkraft. Ihren Anweisungen ist Folge zu leisten. Sie kann eine Führung bei Nichtbeachten dieser Anweisungen auch abbrechen.</li>\r\n</ul>\r\n<br>\r\n<strong>Hinweis für Schulklassen:</strong>\r\n<br>\r\nEs besteht keine Möglichkeit auf dem Gelände der Feuerwachen eine Brotzeit einzunehmen.\r\n\r\n<br>\r\n{% endblock %}\r\n\r\n{% block salutation_german %}\r\nSehr geehrte*r {{ client.familyName }},<br /><br />\r\n{% endblock %}\r\n\r\n{% block salutation_german_neutral %}\r\nGuten Tag {{ client.familyName }},<br /><br />\r\n{% endblock %}\r\n\r\n{% block sendoff_german %}\r\nMit freundlichen Grüßen<br />\r\nIhr {{ process.scope.provider.displayName }} \r\n<br /><br />\r\n{# <a href=\"{{ config.appointments.urlAppointments }}\">{{ config.appointments.urlAppointments }}</a> #}\r\n{% endblock %}\r\n\r\n{% block sendoff_munich %}\r\nMit freundlichen Grüßen<br />\r\nLandeshauptstadt München\r\n<br /><br />\r\n<img src=\"https://assets.muenchen.de/logos/lhm/logo-lhm-muenchen-256.jpg\" alt=\"Logo der Landeshauptstadt München\" width=\"180\" height=\"auto\">\r\n <br /> <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_bb%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nBürgerbüro Meldewesen, Kfz- und Fundangelegenheiten <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396000\">+49 89 233-96000</a> <br />\r\nNachricht: <a href=\"https://service.muenchen.de/intelliform/forms/01/02/02/buergerbuero_kontakt/index\" target=\"_blank\">Kontaktformular Bürgerbüro</a>\r\n <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_kvrbd%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung IV - Branddirektion <br />\r\nPressestelle   <br /><br />\r\nTelefon: <a href=\"tel:+4989235331333\">+49 89 2353 - 31333</a> <br />\r\nMail: <a href=\"mailto:presse.feuerwehr@muenchen.de \" target=\"_blank\">presse.feuerwehr@muenchen.de </a>\r\n <br />\r\nWebsite: <a href=\"https://www.feuerwehr.muenchen.de \" target=\"_blank\">www.feuerwehr.muenchen.de </a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_abh%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nServicestelle für Zuwanderung und Einbürgerung  <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396010\">+49 89 233-96010</a> <br />\r\nNachricht: <a href=\"https://stadt.muenchen.de/infos/online-abh.html\" target=\"_blank\">Kontaktformular</a>\r\n <br />\r\nWebsite: <a href=\"https://stadt.muenchen.de/buergerservice/ausland-migration.html\" target=\"_blank\">Ausland und Migration</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_abh_pass%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nServicestelle für Zuwanderung und Einbürgerung  <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396010\">+49 89 233-96010</a> <br />\r\nNachricht: <a href=\"https://stadt.muenchen.de/infos/online-abh.html\" target=\"_blank\">Kontaktformular</a>\r\n<br />\r\nWebsite: <a href=\"https://stadt.muenchen.de/buergerservice/ausland-migration.html\" target=\"_blank\">Ausland und Migration</a>\r\n<br />\r\n{% endblock %}\r\n\r\n{% block sendoff_ga%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung III Gewerbeangelegenheiten und Verbraucherschutz <br />\r\nServicetelefon: <a href=\"tel:+498923396030\">+49 89 233-96030</a> <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_sta%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nStandesamt <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396060\">+49 89 233-96060</a> <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_kfz_fs%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nFahrzeugzulassungs- und Fahrerlaubnisbehörde <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396090\">+49 89 233-96090</a> <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_fund%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung II Bürgerangelegenheiten <br />\r\nBürgerbüro Meldewesen, Kfz- und Fundangelegenheiten <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396045\">+49 89 233-96045</a> <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_vet%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung III Gewerbeangelegenheiten und Verbraucherschutz <br />\r\nStädtisches Veterinäramt  <br /><br />\r\nServicetelefon: <a href=\"tel:+498923396045\">+49 89 233-96045</a> <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_kvue%}\r\nKreisverwaltungsreferat <br />\r\nHauptabteilung I Sicherheit und Ordnung, Prävention <br />\r\nKommunale Verkehrsüberwachung und Kommunaler Außendienst  <br /><br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_neutral_kvr%}\r\nKreisverwaltungsreferat <br />\r\nWebsite: <a href=\"https://muenchen.de/kvr\" target=\"_blank\">muenchen.de/kvr</a>\r\n <br />\r\n{% endblock %}\r\n\r\n{% block sendoff_neutral_soz%}\r\nSozialreferat <br />\r\n{{ process.scope.provider.displayName }} \r\n<br /><br />\r\n{% endblock %}\r\n{% block sendoff_neutral_rbs%}\r\nReferat für Bildungs und Sport <br />\r\n{{ process.scope.provider.displayName }} \r\n<br /><br />\r\n{% endblock %}\r\n\r\n{% block sendoff_abh_tb %}\r\nServicestelle für Zuwanderung und Einbürgerung<br />\r\nSicherheitsbefragungen<br />\r\nHauptabteilung II Bürgerangelegenheiten<br />\r\nRuppertstraße 19, Eingang A, Tür 2<br />\r\n80337 München<br />\r\nTelefon Sicherheitsbefragungen: 089 233 44159<br />\r\nE-Mail Sicherheitsbefragungen: sze332tb.kvr@muenchen.de<br />\r\n{% endblock %}\r\n\r\n{% block mein_meeting_snippet %}\r\nMit freundlichen Uli Grüßen<br />\r\nIhr {{ process.scope.provider.displayName }} \r\n<br /><br />\r\n{# <a href=\"{{ config.appointments.urlAppointments }}\">{{ config.appointments.urlAppointments }}</a> #}\r\n{% endblock %}\r\n',	'',	'2025-10-24 14:41:27'),
(18,	'subjects.twig',	'{% block german %}\r\n    {% if status == \'confirmed\' or status == \'appointment\' %}\r\n    Bestätigung Ihres Termins {{ process.displayNumber }}\r\n    {% elseif status == \'preconfirmed\' %}\r\n    Aktivieren Sie Ihren Termin!\r\n    {% elseif status == \'reminder\' %}\r\n    Erinnerung an Ihren Termin {{ process.displayNumber }}\r\n    {% elseif (status == \'deleted\' or status == \'blocked\') and not initiator %}\r\n    Absage Ihres Termins {{ process.displayNumber }}\r\n    {% elseif (status == \'deleted\' or status == \'blocked\') and initiator %}\r\n    Information Terminabsage\r\n    {% elseif status == \'updated\' and initiator %}\r\n    Information Terminänderung\r\n    {% elseif status == \'queued\' %}\r\n    Wartenummerbestaetigung\r\n    {% elseif status == \'pickup\' %}\r\n    Ihr Dokument {% if process.requests|first.name %}({{ process.requests|first.name }}) {% endif %}ist fertig und liegt zur Abholung bereit.\r\n    {% elseif status == \'survey\' and process.clients|first.surveyAccepted %}\r\n    Kundenbefragung des Standorts {{ process.scope.contact.name }}\r\n    {% else %}\r\n    Terminerinnerung\r\n    {% endif %}\r\n{% endblock %}\r\n',	'',	'2025-10-08 13:31:56'),
(507,	'mail_preconfirmed.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set confirmLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nwir haben folgenden Termin für Sie reserviert:\r\n<br><br>\r\n---\r\n<br><br>\r\n<strong> Terminnummer: {{ process.displayNumber }} </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n---\r\n<br><br>\r\nAktivieren Sie den Termin innerhalb von {{ process.scope.preferences.appointment.activationDuration }} Minuten, sonst verfällt Ihre Reservierung. Klicken Sie auf den folgenden Link, um Ihre Terminbuchung abzuschließen:\r\n<br>\r\n<strong><a href=\"{{ confirmLink }}\" target=\"_blank\">Termin aktivieren</a></strong>  <br /><br />\r\n\r\nNach Aktivierung des Termins erhalten Sie eine Bestätigung und weitere Informationen zu Ihrem Termin per E-Mail.\r\n<br><br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_abh\") }} \r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'10456',	'2026-02-13 13:38:37'),
(516,	'mail_reminder.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n       Sie haben morgen folgenden Termin bei uns:\r\n        <br><br>\r\n        ---\r\n        <br><br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br><br> {% if process.scope.hint %}\r\n        <strong>{{ process.scope.hint }} </strong>\r\n        {% endif %}\r\n<br><br>\r\n---\r\n<br><br>\r\n<strong>Hinweise zu Ihrem Besuch:</strong>\r\n<br>\r\n<ul>\r\n    {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    {% endif %}\r\n	<li>Bringen Sie alle benötigten Unterlagen zum Termin mit:\r\n   <ul>\r\n    <li>Reisepass (oder Ausweisersatz, Identitätsnachweis)</li>\r\n    <li>bisherige Aufenthaltstitel (ggf. Fiktionsbescheinigungen) und</li>\r\n    <li>gegebenenfalls <a href=\"https://stadt.muenchen.de/dam/jcr:3194b426-9200-4573-91cb-049cb8808d38/Vollmacht_Abholung_eAT.pdf\" target=\"_blank\">Vollmacht</a>: bei Abholung durch Dritte oder durch Minderjährige</li>\r\n  </ul>\r\n  \r\n  </li>\r\n   <li>Stellen Sie sicher, dass Sie mögliche Gebühren direkt vor Ort bezahlen können.</li>\r\n    <li>Kommen Sie bitte pünktlich. Zeigen Sie am Eingang diese E-Mail vor.  </li>\r\n    <li>Ihre Terminnummer wird vor Ort auf einem Bildschirm angezeigt. Sie sehen dort, wann Sie dran sind und wohin Sie gehen müssen.</li>\r\n    <li>In seltenen Fällen kann es vorkommen, dass Sie trotz Termin kurz warten müssen. Bitte haben Sie dafür Verständnis.</li>\r\n</ul>	\r\n<br>\r\n——\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\"><strong>Termin absagen oder verschieben</strong></a><br />\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_abh\") }} \r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}\r\n',	'10456',	'2026-02-13 13:38:37'),
