(1038,	'mail_confirmation.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n       Sie haben folgenden Termin bei uns gebucht:\r\n        <br><br>\r\n        ---\r\n        <br><br>\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n---\r\n<br><br>\r\n<strong>Hinweise zur Vorbereitung:</strong>\r\n<br>\r\n<ul>\r\n    <li>Tragen Sie den Termin in Ihren Kalender ein. Im Anhang finden Sie eine ics-Datei zum Import.</li>\r\n    <li>Vergewissern Sie sich, dass Sie alle Voraussetzungen für die gebuchten Leistungen erfüllen.</li>\r\n    <li>Tragen Sie alle benötigten Unterlagen zusammen und halten Sie sie für Ihren Termin bereit.</li>\r\n</ul>\r\n<br>\r\n---\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{