(1878,	'mail_reminder.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n      Sie haben in Kürze folgenden Termin bei uns:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zu Ihrem Besuch:</strong>\r\n<br>\r\n<ul>\r\n    {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    {% endif %}\r\n	<li>Bringen Sie alle benötigten Unterlagen zum Termin mit. Stellen Sie sicher, dass Sie mögliche Gebühren direkt vor Ort bezahlen können.</li>\r\n    <li>Kommen Sie bitte pünktlich. Zeigen Sie am Eingang diese E-Mail vor.  </li>\r\n    <li>Ihre Terminnummer wird vor Ort auf einem Bildschirm angezeigt. Sie sehen dort, wann Sie dran sind und wohin Sie gehen müssen.</li>\r\n    <li>In seltenen Fällen kann es vorkommen, dass Sie trotz Termin kurz warten müssen. Bitte haben Sie dafür Verständnis.</li>\r\n</ul>\r\n<br>\r\n——\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\"><strong>Termin absagen oder verschieben</strong></a><br />\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_abh\") }}\r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}\r\n',	'10471',	'2026-02-13 13:38:37'),
