(1992,	'mail_delete.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set bookLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nIhr Termin wurde abgesagt:\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong> Terminnummer: {{ process.displayNumber }} </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n——\r\n<br><br>\r\nDanke, dass Sie Ihren Termin für andere freigegeben haben. \r\n<br><br>\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_vet\") }}\r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'1049618',	'2026-02-13 13:38:37'),
(2002,	'icsappointment.twig',	'{% block content %}\r\nBEGIN:VCALENDAR\r\nX-LOTUS-CHARSET:UTF-8\r\nCALSCALE:GREGORIAN\r\nVERSION:2.0\r\nPRODID:ZMS-München\r\nX-WR-TIMEZONE:Europe/Berlin\r\nBEGIN:VTIMEZONE\r\nTZID:Europe/Berlin\r\nX-LIC-LOCATION:Europe/Berlin\r\nBEGIN:DAYLIGHT\r\nTZOFFSETFROM:+0100\r\nTZOFFSETTO:+0200\r\nTZNAME:CEST\r\nDTSTART:19700329T020000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=3\r\nEND:DAYLIGHT\r\nBEGIN:STANDARD\r\nTZOFFSETFROM:+0200\r\nTZOFFSETTO:+0100\r\nTZNAME:CET\r\nDTSTART:19701025T030000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=10\r\nEND:STANDARD\r\nEND:VTIMEZONE\r\nBEGIN:VEVENT\r\nUID:{{ startTime|date(\"Ymd\") }}-{{ process.displayNumber }}\r\nLOCATION: Sie werden zu diesem Zeitpunkt (unter der von Ihnen angegebenen Telefonnummer) von der KITA-Elternberatung zur Kinderbetreuung angerufen\r\nGEO:48.85299;2.36885\r\nSUMMARY:{{ \"München-Termin:\"|trans }} {{ process.displayNumber }}\r\nDESCRIPTION:{{ message }}\r\nCLASS:PUBLIC\r\nDTSTART;TZID=Europe/Berlin:{{ startTime|date(\"Ymd\") }}T{{ startTime|date(\"His\") }}\r\nDTEND;TZID=Europe/Berlin:{{ endTime|date(\"Ymd\") }}T{{ endTime|date(\"His\") }}\r\nDTSTAMP:{{ timestamp|date(\"Ymd\") }}T{{ timestamp|date(\"His\") }}\r\nBEGIN:VALARM\r\nACTION:DISPLAY\r\nDESCRIPTION:{{ \"München-Termin:\"|trans }} {{ process.displayNumber }}\r\nTRIGGER:-P1D\r\nEND:VALARM\r\nSTATUS:CONFIRMED\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n{% endblock %}\r\n',	'1063373',	'2026-02-13 13:38:37'),
(2017,	'mail_confirmation.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"autogenerated_top_german\") }}\r\n        {{ block(\"salutation_german_neutral\") }}\r\n        wir bestätigen Ihren Termin im <strong>{{ process.scope.provider.displayName }}</strong>.\r\n        <br><br>\r\n        {#{{ process.scope.hint }}\r\n        {{ process.scope.shortName }} Die Variablen können für die Behördenspezifishe Texte verwendent verden  #} \r\n        {#\r\n         ~ \", \" ~ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber ~\", \" ~ process.scope.provider.contact.postalCode ~ \" \" ~ process.scope.provider.contact.city }}<br />\r\n        {% if process.scope.hint %}\r\n        ({{ process.scope.hint }})<br />\r\n        {% endif %}<br />\r\n        #}\r\n        Datum:<strong> {{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd. MMMM y\") }} </strong><br>\r\n        Uhrzeit: <strong>{{ (date|default(getNow))|date(\"H:i\") }} {% trans %}Uhr{% endtrans %}</strong>.<br />\r\n        <br>\r\n\r\n              {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br />\r\n        {% if process.scope.hint %}\r\n        <strong>Wartezone: {{ process.scope.hint }} </strong><br />\r\n        {% endif %}<br />\r\n        Bitte gehen Sie rechtzeitig zur <strong>\"{{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\"</strong><br />\r\n        <br>\r\n<strong>Hinweise zur Vorbereitung:</strong>\r\n<br>\r\n<ul>\r\n  {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    <li>Im Anhang finden Sie außerdem eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n   {% endif %}\r\n    <li>Im Anhang finden Sie eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n    <li>Stellen Sie sicher, dass Sie alle Voraussetzungen für die gebuchten Leistungen erfüllen.</li>\r\n    <li>Bringen Sie alle benötigten Unterlagen zum Termin mit.</li>\r\n</ul>\r\n        <p>\r\n        Bitte melden Sie sich grundsätzlich im entsprechenden Zimmer für Ihren Buchstabenbereich. Beachten Sie bitte, dass es möglicherweise kurzfristige Änderungen bei der Zuordnung \r\n        der Buchstabenbereiche zu den Zimmernummern geben kann. Informationsaushänge vor Ort sollten beachtet werden. Die Ausstellung und Verlängerung von Fischereischeinen sowie die \r\n        Verlängerung von Jagdscheinen erfolgen normalerweise im Zimmer Nr. 42.14. Falls dieses Zimmer nicht besetzt ist oder wenn Sie andere Dienstleistungen im Bereich Waffen-, Jagd-, \r\n        Fischerei- und Sprengstoffwesen benötigen, \r\ngelten die unten aufgeführten Buchstabenbereiche:\r\n        </p>\r\n\r\n<table>\r\n\r\n<tr>\r\n<th align=\"left\">von</th>\r\n<th align=\"left\">bis</th>\r\n<th align=\"left\">Zimmer Nr.</th>\r\n</tr>\r\n\r\n  <tr>\r\n    <td>A</td>\r\n	<td>Bob  </td>\r\n    <td>42.38</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Boc</td>\r\n	<td>Hoq</td>\r\n    <td>42.47</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Hor &nbsp;&nbsp;&nbsp;&nbsp;</td>\r\n	<td>Ra &nbsp;&nbsp;&nbsp;&nbsp;</td>\r\n    <td>42.45</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Rb  </td>\r\n	<td>Z   </td>\r\n    <td>42.43</td>\r\n  </tr>  \r\n</table>\r\n\r\n<br /><br />\r\n\r\n        {#Ihre Vorgangsnummer ist die <strong>\"{{ process.displayNumber }}\"</strong><br />\r\n        <br />#}\r\n        \r\n        {#{% if config.appointments.sms.telephone %}\r\n            Oder schicken Sie eine SMS mit dem Inhalt \"{{ config.appointments.sms.textCancel }}\\{{ process.displayNumber }}\" an die Rufnummer {{ config.appointments.sms.telephone }}.\r\n            \"Hierbei ist die Groß- und Kleinschreibung von \"{{ config.appointments.sms.textCancel }}\" nicht wichtig. Bei Absage per SMS erhalten Sie zu Ihrer Sicherheit eine Bestätigungs-SMS Ihrer Absage.<br />\r\n            <br />\r\n        {% endif %}\r\n        #}\r\n        {#{% if process.scope.provider.source == \"dldb\" and process.scope.provider.data.payment %}\r\n            Zahlungshinweis: {{ process.scope.provider.data.payment }}<br /><br />\r\n        {% endif %}#}\r\n        {% if process.requests|length > 1 %}\r\n            {% set requestalias = \"Dienstleistungen sind\" %}\r\n        {% else %}\r\n            {% set requestalias = \"Dienstleistung ist\" %}\r\n        {% endif %}\r\n        {% if process.requests|length == 0 %}\r\n            Sie haben keine Dienstleistungen ausgewählt.\r\n        {% else %}\r\n            Folgende {{ requestalias }} für diesen Termin gebucht:\r\n            <br/><br />\r\n            {% for requestGroup in requestGroups %}\r\n                <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} {#am Standort {{ process.scope.provider.displayName }}#}</a></strong><br/>\r\n                \r\n                Anzahl: {{ requestGroup[\'count\'] }}\r\n                \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n                    <br /><br />\r\n                    ----------------------\r\n                    <br /><br />\r\n                {% endif %}\r\n            {% endfor %}\r\n        {% endif %}\r\n        <br><br>\r\n        Bitte informieren Sie sich vorab über oben genannte/n Link/s, welche Unterlagen Sie benötigen. \r\n        <br> <br>\r\n        Falls Sie diesen Termin nicht benötigen oder wahrnehmen können, stornieren Sie bitte <b>umgehend</b> Ihren Termin und reservieren einen neuen Termin.\r\n        <a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\">Termin umbuchen/absagen</a><br />\r\n        <br /><br />\r\n\r\n        {{ block(\"sendoff_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}',	'10517',	'2026-02-13 13:38:37'),
(2020,	'mail_reminder.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"autogenerated_top_german\") }}\r\n{{ block(\"salutation_german_neutral\") }}\r\nwir erinnern Sie an Ihren Termin  <strong>am {{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd. MMMM y\") }} {% trans %}um{% endtrans %} {{ (date|default(getNow))|date(\"H:i\") }} {% trans %}Uhr{% endtrans %}</strong>. <br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n<br />\r\n{% if process.scope.hint %}\r\n<strong>Wartezone: {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<strong>Hinweise zu Ihrem Besuch:</strong>\r\n<br>\r\n<ul>\r\n    {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    {% endif %}\r\n	  <li>Bringen Sie alle benötigten Unterlagen zum Termin mit.</li>\r\n    <li>Kommen Sie bitte pünktlich. Zeigen Sie am Eingang diese E-Mail vor.  </li>\r\n    <li>In seltenen Fällen kann es vorkommen, dass Sie trotz Termin kurz warten müssen. Bitte haben Sie dafür Verständnis.</li>\r\n</ul>	\r\nBitte gehen Sie rechtzeitig zur <strong>\"{{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\"</strong><br />\r\n<br>\r\n\r\n        <p>\r\n        Bitte melden Sie sich grundsätzlich im entsprechenden Zimmer für Ihren Buchstabenbereich. Beachten Sie bitte, dass es möglicherweise kurzfristige Änderungen bei der Zuordnung \r\n        der Buchstabenbereiche zu den Zimmernummern geben kann. Informationsaushänge vor Ort sollten beachtet werden. Die Ausstellung und Verlängerung von Fischereischeinen sowie die \r\n        Verlängerung von Jagdscheinen erfolgen normalerweise im Zimmer Nr. 42.14. Falls dieses Zimmer nicht besetzt ist oder wenn Sie andere Dienstleistungen im Bereich Waffen-, Jagd-, \r\n        Fischerei- und Sprengstoffwesen benötigen, \r\ngelten die unten aufgeführten Buchstabenbereiche:\r\n        </p>\r\n\r\n<table>\r\n\r\n<tr>\r\n<th align=\"left\">von</th>\r\n<th align=\"left\">bis</th>\r\n<th align=\"left\">Zimmer Nr.</th>\r\n</tr>\r\n\r\n  <tr>\r\n    <td>A</td>\r\n	<td>Bob  </td>\r\n    <td>42.38</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Boc</td>\r\n	<td>Hoq</td>\r\n    <td>42.47</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Hor &nbsp;&nbsp;&nbsp;&nbsp;</td>\r\n	<td>Ra &nbsp;&nbsp;&nbsp;&nbsp;</td>\r\n    <td>42.45</td>\r\n  </tr>\r\n  <tr>\r\n    <td>Rb  </td>\r\n	<td>Z   </td>\r\n    <td>42.43</td>\r\n  </tr>  \r\n</table>\r\n\r\n<br /><br />\r\n\r\nBitte erscheinen Sie rechtzeitig zu Ihrem Termin und zeigen diese Terminerinnerung beim Einlass vor. \r\n<br /><br />\r\n\r\n\r\n {% if process.requests|length > 1 %}\r\n            {% set requestalias = \"Dienstleistungen sind\" %}\r\n        {% else %}\r\n            {% set requestalias = \"Dienstleistung ist\" %}\r\n        {% endif %}\r\n        {% if process.requests|length == 0 %}\r\n            Sie haben keine Dienstleistungen ausgewählt.\r\n        {% else %}\r\n            Folgende {{ requestalias }} für diesen Termin gebucht:\r\n            <br/><br />\r\n            {% for requestGroup in requestGroups %}\r\n                <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} {#am Standort {{ process.scope.provider.displayName }}#}</a></strong><br/>\r\n                \r\n                Anzahl: {{ requestGroup[\'count\'] }}\r\n                \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n                    <br /><br />\r\n                    ----------------------\r\n                    <br /><br />\r\n                {% endif %}\r\n            {% endfor %}\r\n        {% endif %}\r\n        <br><br>\r\n        Bitte vergewissern Sie sich über oben genannte/n Link/s, welche Unterlagen Sie benötigen und halten Sie diese für Ihren Termin bereit. \r\n        <br><br>\r\n        Hinweise: \r\n        <br><br>\r\n        Bei erhöhtem Kundenaufkommen können wir leider nicht ausschließen, dass Sie trotz Termins mit einer geringen Wartezeit rechnen müssen. Wir bitten Sie hierfür um Verständnis.\r\n        <br><br>\r\n        Falls Sie diesen Termin nicht benötigen oder wahrnehmen können, stornieren Sie bitte <b>umgehend</b> Ihren Termin und reservieren einen neuen Termin.\r\n        <a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\">Termin umbuchen/absagen</a><br />\r\n        <br /><br />\r\n{{ block(\"sendoff_german\") }}\r\n</div>\r\n{% endblock %}\r\n',	'10517',	'2026-02-13 13:38:37'),
