(2165,	'icsappointment.twig',	'{% block content %}\r\nBEGIN:VCALENDAR\r\nX-LOTUS-CHARSET:UTF-8\r\nCALSCALE:GREGORIAN\r\nVERSION:2.0\r\nPRODID:ZMS-München\r\nX-WR-TIMEZONE:Europe/Berlin\r\nBEGIN:VTIMEZONE\r\nTZID:Europe/Berlin\r\nX-LIC-LOCATION:Europe/Berlin\r\nBEGIN:DAYLIGHT\r\nTZOFFSETFROM:+0100\r\nTZOFFSETTO:+0200\r\nTZNAME:CEST\r\nDTSTART:19700329T020000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=3\r\nEND:DAYLIGHT\r\nBEGIN:STANDARD\r\nTZOFFSETFROM:+0200\r\nTZOFFSETTO:+0100\r\nTZNAME:CET\r\nDTSTART:19701025T030000\r\nRRULE:FREQ=YEARLY;INTERVAL=1;BYDAY=-1SU;BYMONTH=10\r\nEND:STANDARD\r\nEND:VTIMEZONE\r\nBEGIN:VEVENT\r\nUID:{{ startTime|date(\"Ymd\") }}-{{ process.displayNumber }}\r\nORGANIZER;CN=\"Landeshauptstadt München\":MAILTO:{{ process.scope.preferences.client.emailFrom }}\r\nSEQUENCE:0\r\nLOCATION:{{ process.scope.provider.displayName }} {{ process.scope.provider.contact.street }} {{ process.scope.provider.contact.streetNumber }}\\, {{ process.scope.provider.contact.postalCode }} {{ process.scope.provider.contact.city }}\r\nGEO:48.85299;2.36885\r\nSUMMARY: {{ process.requests|reduce((carry, req) => carry|merge({ (req.name): (carry[req.name] is defined ? carry[req.name] + 1 : 1) }), {})|map((count, name) => (count > 1 ? count ~ \'x \' : \'\') ~ name)|join(\', \') }} \r\nDESCRIPTION: {{ process.scope.provider.displayName }}\\n{{ (date|default(getNow)|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\")) }}\\n{{ process.clients[0].email }}\\n{{ process.clients[0].telephone }}\\n{{ process.customTextfield }}\r\nCLASS:PUBLIC\r\nDTSTART;TZID=Europe/Berlin:{{ startTime|date(\"Ymd\") }}T{{ startTime|date(\"His\") }}\r\nDTEND;TZID=Europe/Berlin:{{ endTime|date(\"Ymd\") }}T{{ endTime|date(\"His\") }}\r\nDTSTAMP:{{ timestamp|date(\"Ymd\") }}T{{ timestamp|date(\"His\") }}\r\nBEGIN:VALARM\r\nACTION:DISPLAY\r\nDESCRIPTION:{{ \"München-Termin123:\"|trans }} {{ process.displayNumber }}\r\nTRIGGER:-P1D\r\nEND:VALARM\r\nSTATUS:CONFIRMED\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n{% endblock %}',	'10222269',	'2026-02-13 13:38:37'),
