(2982,	'mail_reminder.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n      Sie haben in Kürze folgenden Termin bei uns:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zu Ihrem Besuch:</strong>\r\n<br>\r\n<ul>\r\n    {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    {% endif %}\r\n	<li>Bringen Sie alle benötigten Unterlagen zum Termin mit. Stellen Sie sicher, dass Sie mögliche Gebühren direkt vor Ort bezahlen können.</li>\r\n    <li>Kommen Sie bitte pünktlich. Zeigen Sie am Eingang diese E-Mail vor.  </li>\r\n    <li>Ihre Terminnummer wird vor Ort auf einem Bildschirm angezeigt. Sie sehen dort, wann Sie dran sind und wohin Sie gehen müssen.</li>\r\n    <li>In seltenen Fällen kann es vorkommen, dass Sie trotz Termin kurz warten müssen. Bitte haben Sie dafür Verständnis.</li>\r\n</ul>\r\n<br>\r\n\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_abh\") }}\r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}',	'10455',	'2026-02-13 13:38:37'),
(2985,	'mail_confirmation.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n       Sie haben folgenden Termin bei uns gebucht:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zur Vorbereitung:</strong>\r\n<br>\r\n<ul>\r\n  {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    <li>Im Anhang finden Sie außerdem eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n   {% endif %}\r\n    <li>Im Anhang finden Sie eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n    <li>Stellen Sie sicher, dass Sie alle Voraussetzungen für die gebuchten Leistungen erfüllen.</li>\r\n     <li>Bringen Sie alle benötigten Unterlagen zum Termin mit. Wichtig: Für Ausweisdokumente, elektronische Aufenthaltstitel und Reiseausweise benötigen Sie ab 1. Mai 2025 ein <a href=\"https://stadt.muenchen.de/news/digitale-passbilder.html\" target=\"_blank\">digitales Passfoto</a>.</li>\r\n</ul>\r\n<br>\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"sendoff_abh\") }} \r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}\r\n',	'10308685',	'2026-02-13 13:38:37'),
(2988,	'mail_admin_delete.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n<div style=\"color: #000000; background: #ffffff;\">\r\n{{ block(\"salutation_german_neutral\") }}\r\n{% set bookLink = config.appointments.urlAppointments ~ \'#/appointment/confirm/\' ~ appointmentLink  %}\r\nwir mussten Ihren Termin absagen.\r\n<br><br>\r\n—\r\n<br><br>\r\n<strong> Terminnummer: {{ process.displayNumber }} </strong> \r\n<br>\r\n{% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"http://www.muenchen.de/dienstleistungsfinder/muenchen/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n ,\r\n                {% else %}\r\n<br>\r\n                {% endif %}\r\n\r\n{% endfor %}\r\n{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>{{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}\r\n<br><br>\r\n---\r\n<br><br>\r\nSie erfüllen nicht die Voraussetzungen für die gebuchte Dienstleistung (Abholung der Einbürgerungsurkunde) oder Sie haben mehrere Termine für dieselbe Dienstleistung gebucht.<br>\r\n<br>\r\nBitte beachten Sie, dass keine Termine für die Beantragung der Einbürgerung, für Beratungsgespräche oder für Sachstandsanfragen vergeben werden. Für Rückfragen nutzen Sie bitte ausschließlich \r\ndas <a href=\"https://service.muenchen.de/intelliform/forms/01/02/02/einbuergerung_kontakt/index\" target=\"_blank\">Kontaktformular</a> auf unserer <a href=\"https://stadt.muenchen.de/service/info/einburgerungsbehorde/1080548\" target=\"_blank\">Internetseite</a>.\r\n<br><br>\r\n\r\n\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n{{ block(\"autogenerated_down_german\") }}\r\n</div>\r\n<script type=\"application/ld+json\">\r\n{\r\n  \"@context\": \"http://schema.org\",\r\n  \"@type\": \"EventReservation\",\r\n  \"reservationNumber\": \"{{ process.displayNumber }}\",\r\n  \"reservationStatus\": \"http://schema.org/Confirmed\",\r\n  \"modifyReservationUrl\": \"{{ config.appointments.urlAppointments }}\",\r\n  \"modifiedTime\": \"{{ process.createTimestamp|date(\'c\') }}\",\r\n  \"underName\": {\r\n    \"@type\": \"Person\",\r\n    \"name\": \"{{ client.familyName }}\"\r\n  },\r\n  \"reservationFor\": {\r\n    \"@type\": \"Event\",\r\n    \"name\": \"{% for request in process.requests %}{{ request.name }}{% if not loop.last %},{% endif %} {% endfor %}\",\r\n    \"startDate\": \"{{ date|date(\'c\') }}\",\r\n    \"location\": {\r\n      \"@type\": \"Place\",\r\n      \"name\": \"{{ process.scope.provider.name }}\",\r\n      \"url\": \"{{process.scope.provider.link}}\",\r\n      \"geo\": {\r\n        \"@type\": \"GeoCoordinates\",\r\n        \"latitude\": \"{{process.scope.provider.contact.lat}}\",\r\n        \"longitude\": \"{{process.scope.provider.contact.lon}}\"\r\n      },\r\n      \"address\": {\r\n        \"@type\": \"PostalAddress\",\r\n        \"streetAddress\": \"{{process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber}}\",\r\n        \"addressLocality\": \"{{process.scope.provider.contact.city}}\",\r\n        \"addressRegion\": \"{{process.scope.provider.contact.city}}\",\r\n        \"postalCode\": \"{{process.scope.provider.contact.postalCode}}\",\r\n        \"addressCountry\": \"DE\"\r\n      }\r\n    }\r\n  }\r\n}\r\n</script>\r\n{% endblock %}\r\n',	'10471',	'2025-10-27 09:34:08'),
(2989,	'mail_confirmation.twig',	'{% use \"snippets.twig\" %}\r\n{% block german %}\r\n    <div style=\"color: #000000; background: #ffffff;\">\r\n        {{ block(\"salutation_german_neutral\") }}\r\n       Sie haben folgenden Termin bei der Feuerwehr München gebucht:\r\n        <br><br>\r\n        ——\r\n        <br><br>\r\n       {% if process.externalUserId is defined and process.externalUserId != null %}\r\n       <strong> Terminnummer: </strong> <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">{{ process.displayNumber }}</a>\r\n       {% else %}\r\n       <strong> Terminnummer: </strong> {{ process.displayNumber }} \r\n       {% endif %}\r\n        <br><br>\r\n        <strong> Leistung: </strong>\r\n        <br>\r\n        {% for requestGroup in requestGroups %}\r\n         {{ requestGroup[\'count\'] }}x <strong><a href=\"https://stadt.muenchen.de/service/info/{{ requestGroup[\'request\'].id }}/\">{{ requestGroup[\'request\'].name }} </a></strong><br/>           \r\n                {% if requestGroups|length > 1 and not loop.last %}\r\n        \r\n                {% endif %}\r\n\r\n        {% endfor %}\r\n        <br>\r\n{% if process.customTextfield or process.customTextfield2 %}\r\n<strong> Ihre Angaben: </strong>\r\n{% if process.customTextfield %}\r\n<br>Geburtsdatum: {{ process.customTextfield }}\r\n{% endif %}\r\n{% if process.customTextfield2 %}\r\n<br>Standort(e): {{ process.customTextfield2 }}\r\n{% endif %}\r\n<br><br>\r\n{% endif %}\r\n<strong> Zeit: </strong>\r\n<br>{{ (date|default(getNow))|format_date(locale=\"de\", pattern=\"EEEE, dd.MM.yyyy, HH:mm \'Uhr\'\") }}\r\n<br>\r\n<br><strong> Ort: </strong>\r\n<br>Feuerwache 5, {{ process.scope.provider.displayName }}, {{ process.scope.provider.contact.street ~ \" \"  ~ process.scope.provider.contact.streetNumber }}, {{process.scope.provider.contact.postalCode}}, {{process.scope.provider.contact.city}}, Eingang über Nachrichtenstelle an der Ecke zur Anzinger Straße\r\n<br>{% if process.scope.hint %}\r\n<strong> {{ process.scope.hint }} </strong><br />\r\n{% endif %}<br />\r\n<br><br>\r\n——\r\n<br><br>\r\n<strong>Hinweise zur Vorbereitung:</strong>\r\n<br>\r\n<ul>\r\n  {% if process.externalUserId is defined and process.externalUserId != null %}\r\n    <li>Alle <a href=\"https://stadt.muenchen.de/mein-bereich/termine/termin-detail?ap-id={{ process.displayNumber }}\">Informationen zu Ihrem Termin</a> können Sie jederzeit in Ihrem Bereich einsehen.</li>\r\n    <li>Im Anhang finden Sie außerdem eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n   {% endif %}\r\n    <li>Im Anhang finden Sie eine ics-Datei zum Import des Termins in Ihren Kalender.</li>\r\n    <li>Sollten Sie ein Einweisungsbüchlein zur Unterschrift besitzen, so bringen Sie dies bitte zum Termin mit.</li>\r\n</ul>\r\n<br>\r\n——\r\n<br><br>\r\nIhnen ist etwas dazwischengekommen? Dann geben Sie uns Bescheid:\r\n<br><a href=\"{{ config.appointments.urlAppointments }}#/appointment/{{ appointmentLink }}\"><strong>Termin absagen oder verschieben</strong></a><br />\r\n<br>\r\n\r\n{{ block(\"sendoff_munich\") }}\r\n {#{{ block(\"sendoff_bb\") }}  je nach Behörde#}\r\n{{ block(\"autogenerated_down_german\") }}\r\n    </div>\r\n    \r\n{% endblock %}\r\n',	'10433938',	'2026-03-23 09:31:53'),
